#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a1,a2,a3,b1,b2,b3; 
        scanf("%d %d %d", &a1, &a2, &a3);
        scanf("%d %d %d", &b1, &b2, &b3);
        int cntA = a1 + a2 + a3;
        int cntB = b1 + b2 + b3;
        if(cntA == cntB) printf("Pass\n");
        else printf("Fail\n");
    }
    return 0;
}

